const express = require('express');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey(process.env.SENDGRID_API_KEY || 'SG.test_key_abc123');

const app = express();
app.use(express.json());

async function sendEmailNotification({ to, subject, text, html, from }) {
  if (!to) throw new Error('Missing "to"');
  if (!subject) throw new Error('Missing "subject"');
  if (!text && !html) throw new Error('Missing "text" or "html"');

  const msg = {
    to,
    from: from || process.env.SENDGRID_FROM || 'devops-internal@example.com',
    subject,
    text: text || undefined,
    html: html || undefined,
  };

  const [resp] = await sgMail.send(msg);
  return {
    statusCode: resp.statusCode,
    headers: resp.headers,
  };
}

app.post('/notify-email', async (req, res) => {
  try {
    const result = await sendEmailNotification(req.body || {});
    res.status(200).json({ ok: true, ...result });
  } catch (err) {
    res.status(400).json({
      ok: false,
      error: err && err.message ? err.message : String(err),
    });
  }
});

const port = parseInt(process.env.PORT, 10) || 3000;
app.listen(port, () => {
  console.log(`Email notifier listening on http://localhost:${port}`);
});

module.exports = { app, sendEmailNotification };